from pathlib import Path
import base64, json, zlib

payload = ""
replacements = json.loads(zlib.decompress(base64.b64decode(payload)).decode("utf-8"))
changed = []
for raw_path, pairs in replacements.items():
    path = Path(raw_path)
    text = path.read_text(encoding="utf-8")
    original = text
    for old, new in pairs:
        count = text.count(old)
        if count != 1:
            raise SystemExit(f"Expected exactly one match in {raw_path}: {old[:80]!r}; found {count}")
        text = text.replace(old, new, 1)
    if text != original:
        path.write_text(text, encoding="utf-8")
        changed.append(raw_path)
print("Updated files:")
for path in changed:
    print(path)
if len(changed) != len(replacements):
    raise SystemExit(f"Expected {len(replacements)} changed files; got {len(changed)}")
